import React, { useEffect, useState } from 'react';
import Card from './Card'; 
import '../style/CardWithData.css';
import { FilterProvider ,useFilterContext} from '../ContextApi/FilterApi';
const CardWithData = () => {
    const [data, setData] = useState([]);

    const context = useFilterContext();

    useEffect(() => {
        const fetchData = async () => {
            try {
                const fixed ="http://localhost:8000/Menu"
                const response = await fetch(`${fixed}?filter=${context.category}`);
                const result = await response.json();
                setData(result);
            } catch (error) {
                console.error("Error fetching data: ", error);
            }
        };

        fetchData();
    }, [context.category]);

    return (
        <div className="cards-container">
            {data.length === 0 ? (
                <p>Loading data...</p>
            ) : (
                data.map((item) => (
                    <Card
                        // key={item.id}
                        //imgSrc={item.imgSrc}
                        name={item.item}
                        price={item.price}
                        //description={item.description}
                    />
                ))
            )}
        </div>
    );
};

export default CardWithData;
